#include <stdio.h>
#include <stdlib.h>
int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int g = arr[0];
    for (int i = 1; i < n; i++) {
        g = gcd(g, arr[i]);
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        count += arr[i] / g - 1;
    }
    printf("%d\n", count);
    return 0;
}

